VALUES
  ('dietitian-moex-07034', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '依據行政院衛生署（現為衛生福利部）2011 年修訂最新版「國人膳食營養素參考建議攝取量」，1 歲以 下嬰兒的動物性蛋白攝取量在總蛋白質的比例，應占多少？ 1/2  1/3  2/3  1/4', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07035', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '同重量的早產兒及一般標準的嬰兒配方奶粉的比較，下列敘述何者正確？ 早產兒配方奶粉提供的能量較多 早產兒配方奶粉提供的蛋白質較少 兩種配方奶粉提供的鈣質一樣多 兩種配方奶粉提供的脂肪皆以植物油脂及中鏈油脂為主', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07036', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關楓漿尿症（maple syrup urine disease）的新生兒，下列敘述何者錯誤？ 屬於衛生福利部國民健康署目前所提供補助之新生兒篩檢項目 因體液和尿液會有楓樹糖漿的甜味因而命名 屬於芳香族胺基酸代謝異常的罕見疾病 配方奶粉應補充纈胺酸、白胺酸及異白胺酸', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07037', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '花青素（anthocyanidins）為水溶性之天然色素，而前花青素（proanthocyanidins）之特色為何？ 無色，但於酸性下加以熱處理可以轉化為紅色 前花青素遇到胃酸即可被轉化為花青素 前花青素遇到膽汁即可被轉化為花青素 前花青素為油溶性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07038', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於sports anemia的敘述，下列何者正確？ 並非真正的「iron-deficient」anemia  必需長時間、給與高劑量鐵的治療 主要是因高溫下大量流汗導致鐵的流失所造成的  各類型的運動選手都會發生', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07039', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於運動時，肌肉中肝醣的角色，下列敘述何者正確？ 是肌肉細胞之主要能量來源 會釋放至血液中，作為腦細胞能量之來源 會釋放至血液中，作為合成肝臟中肝醣的原料 作為當進行高強度運動時，維持正常心臟及肺臟功能所需之能量來源', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07040', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '植物固醇存在於植物性蔬果中，已被發現具有調降血膽固醇之功效，最主要可能原因為： 植物固醇與膽固醇具有競爭性，可以減少膽固醇之吸收 植物固醇可以抑制膽固醇之生合成 植物固醇可以促進膽固醇之排泄 植物固醇可以促進膽固醇之消化', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07041', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '運動過程中，下列何種荷爾蒙主要作用在脂肪細胞並促使分解成為脂肪酸以作為能量之來源？ epinephrine  glucagon  leptin  neuropeptide-Y', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07042', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於運動時脂質所扮演的角色，下列敘述何者最為正確？ 最接近肌肉的體脂肪層會先被氧化，當作能量的來源 脂質是長時間進行中強度運動時最主要的能量來源 隨著運動強度的增加，脂質氧化作為能量的比率也隨之增加 脂質氧化的量，於進行高強度短時間運動比低強度長時間運動時來得多', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07043', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關基礎代謝率（basal metabolic rate）的敘述，何者錯誤？ 休息狀態下維持生命所需的基本能量  男性的基礎代謝率高於女性 飢餓狀態下的基礎代謝率會增加  懷孕期間的基礎代謝率會增加', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
